import scala.xml._

class ConfigParserService {

  def parseConfig(xmlString: String): Map[String, String] = {
    val xml: Elem = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(xml: NodeSeq): Map[String, String] = {
    xml.collect {
      case e @ <setting>{name}</setting> => name.text -> extractValue(e)
    }.toMap
  }

  private def extractValue(setting: Node): String = {
    setting.child match {
      case Text(value) => value.trim
      case _ => throw new IllegalArgumentException("Invalid setting format")
    }
  }
}

object ConfigParserService {
  def apply(): ConfigParserService = new ConfigParserService()
